`resolve_and_validate_host` receives a full URL (e.g., `http://127.0.0.1`) via `merged_config["endpoint_url"]` at line 676, but passes it directly to `socket.getaddrinfo(host, None)` at line 436. `getaddrinfo` expects a hostname, not a URL. Need to parse the URL first to extract the hostname.

```suggestion
def resolve_and_validate_host(url: str) -> None:
    """Ensure provided URL points to a non-internal IP."""
    from urllib.parse import urlparse

    parsed = urlparse(url)
    host = parsed.hostname
    if not host:
        raise ValueError(f"Could not extract hostname from URL: '{url}'")

    try:
        # getaddrinfo supports both ipv4 and ipv6
        results = socket.getaddrinfo(host, None)
    except socket.gaierror as e:
        raise ValueError(f"Could not resolve '{host}': {e}") from e

    # Keeps only unique ips from the result tuple
    resolved_ips = {r[4][0] for r in results}

    for ip in resolved_ips:
        try:
            addr = ipaddress.ip_address(ip)
        except ValueError:
            raise ValueError("Could not parse IP")

        if any(addr in network for network in INTERNAL_NETWORKS):
            raise ValueError(f"'{host}' resolved to internal IP: {ip}")
