		var result base.ApiResponse[any]
		if err := json.NewDecoder(resp.Body).Decode(&result); err == nil {
			if resultBytes, err := json.MarshalIndent(result.Data, "", "  "); err == nil {
				fmt.Println(string(resultBytes))
			}
		}
		return nil
	}

